INSERT INTO public.matches (id, user_a_id, user_b_id, status, score, created_at, updated_at, group_id, draft_message_a, draft_message_b, user_a_opted_in, user_b_opted_in, user_a_declined, user_b_declined, intent_score, match_reason, similarity_score) VALUES ('8a1391cf-22f2-4017-a113-e6fa1289f637', '754b5217-2f2b-4461-8952-f557c640ca61', 'fcbeee43-fe8b-48a3-8730-fa0730b961a0', 'notified', NULL, '2026-03-05 23:17:40.632', '2026-03-05 23:50:22.092', 'sb_group_d745e244-6bed-456c-a023-8867cf91fd9e', 'hey rashid, i just met kunal and immediately thought of you. he''s building a superconnector and you might find it interesting. want to connect? ', 'kunal, since you''re building that superconnector you should meet Rashid, a founding engineer at Cocomo. Let me know if you''re interested! ', true, true, false, false, NULL, NULL, NULL);
