INSERT INTO public.matches (id, user_a_id, user_b_id, status, score, created_at, updated_at, group_id, draft_message_a, draft_message_b, user_a_opted_in, user_b_opted_in, user_a_declined, user_b_declined, intent_score, match_reason, similarity_score) VALUES ('b7812090-f3ca-4965-8dde-37a736720425', '5efc529c-d728-4e20-953d-25691d7012a9', '754b5217-2f2b-4461-8952-f557c640ca61', 'suggested', 0.779, '2026-03-11 17:05:54.52', '2026-03-12 22:57:32.978', NULL, NULL, NULL, false, false, false, false, 1, 'Kishan and Rashid can bridge product psychology and technical execution by connecting Kishan’s expertise in communication software with Rashid’s development of AI-driven interview tools and advanced bot detection systems.', 0.632);
